// 【VIP规则：低绝对收益斩杀】（替代原低收益分段考核）
(maindata, torrent) => {
  const categoryList = ["不删", "keep"];

  // 新考核表：基于下载进度（progress）考核已赚到的总上传量（uploadedMiB 单位：MB）
  // 逻辑：不再看盈亏比例，只看真实“赚了多少”。如果没有赚到预期的底线流量，就淘汰。
  const ruleData = [
    { progress: 0.8, minUploadedMiB: 5000 }, // 进度 80% 了，总上传量还没攒够 5000 MB (约5GB)
    { progress: 0.5, minUploadedMiB: 2000 }, // 进度 50% 了，总上传量还没攒够 2000 MB (约2GB)
    { progress: 0.3, minUploadedMiB: 500 }   // 进度 30% 了，总上传量还没攒够 500 MB
  ];

  const { state, upspeed, category, progress, uploaded } = torrent.originProp;

  if (categoryList.indexOf(category) !== -1) {
    return false;
  }

  for (const rule of ruleData) {
    if (
      (state === "downloading" || state === "forcedDL" || state === "stalledDL" || state === "allocating") &&
      progress >= rule.progress &&
      uploaded <= util.calSize(rule.minUploadedMiB, "MiB") &&
      upspeed <= util.calSize(2, "MiB") // 且当前上传速度低于2MB/s（防止当前正在爆发高潮被误杀）
    ) {
      return true; 
    }
  }
  return false;
};
